class Solution:
    def maxResult(self, nums, k):
        n = len(nums)
        NEG = float('-inf')
        best = [NEG] * n
        best[0] = nums[0]
        for i in range(1, n):
            hi = NEG
            for j in range(max(0, i - k), i):
                if best[j] > hi:
                    hi = best[j]
            best[i] = hi + nums[i]
        return best[-1]

