var maxResult = function(nums, k) {
  const n = nums.length;
  const dp = new Array(n).fill(0);
  dp[0] = nums[0];
  const dq = new Array(n);
  let head = 0, tail = 0;
  dq[tail++] = 0;
  for (let i = 1; i < n; i++) {
    while (head < tail && dq[head] < i - k) head++;
    dp[i] = dp[dq[head]] + nums[i];
    while (head < tail && dp[dq[tail - 1]] <= dp[i]) tail--;
    dq[tail++] = i;
  }
  return dp[n - 1];
};
